-- Concatenar strings com +
SELECT Nome + ' ' + Sobrenome AS NomeCompleto
FROM Clientes;

-- CONCAT — mais seguro (trata NULLs)
SELECT CONCAT(Nome, ' ', Sobrenome) AS NomeCompleto
FROM Clientes;

-- STRING_AGG — juntar linhas em uma string (T-SQL 2017+)
SELECT STRING_AGG(Cidade, ', ') AS Cidades
FROM (SELECT DISTINCT Cidade FROM Clientes) AS sub;
-- Resultado: 'São Paulo, Rio de Janeiro, Curitiba'
